1	<!DOCTYPE html>
2	<html lang="zh-CN">
3	<head>
4	    <meta charset="UTF-8">
5	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	    <title>Harness Console</title>
7	    <style>
8	        :root {
9	            --bg-base: #0a0e1a;
10	            --bg-surface: #111827;
11	            --bg-elevated: #1a2236;
12	            --bg-hover: #1e2a42;
13	            --border: rgba(148,163,184,0.10);
14	            --border-strong: rgba(148,163,184,0.20);
15	            --text-primary: #f1f5f9;
16	            --text-secondary: #94a3b8;
17	            --text-muted: #64748b;
18	            --accent: #06b6d4;
19	            --accent-soft: rgba(6,182,212,0.12);
20	            --accent-glow: rgba(6,182,212,0.25);
21	            --green: #22c55e;
22	            --green-soft: rgba(34,197,94,0.12);
23	            --amber: #f59e0b;
24	            --amber-soft: rgba(245,158,11,0.12);
25	            --rose: #f43f5e;
26	            --rose-soft: rgba(244,63,94,0.12);
27	            --blue: #3b82f6;
28	            --blue-soft: rgba(59,130,246,0.12);
29	            --purple: #a78bfa;
30	            --radius-sm: 8px;
31	            --radius-md: 12px;
32	            --radius-lg: 16px;
33	            --radius-xl: 20px;
34	            --shadow-sm: 0 1px 2px rgba(0,0,0,0.3);
35	            --shadow-md: 0 4px 12px rgba(0,0,0,0.4);
36	            --shadow-lg: 0 8px 32px rgba(0,0,0,0.5);
37	            --transition: 0.2s cubic-bezier(0.4,0,0.2,1);
38	        }
39	
40	        * { box-sizing: border-box; margin: 0; padding: 0; }
41	        html { color-scheme: dark; scroll-behavior: smooth; }
42	
43	        body {
44	            min-height: 100vh;
45	            color: var(--text-primary);
46	            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "Inter", sans-serif;
47	            font-size: 14px;
48	            line-height: 1.5;
49	            background: var(--bg-base);
50	        }
51	
52	        h1,h2,h3,h4 { font-weight: 600; letter-spacing: -0.01em; }
53	        button,input,textarea,select { font: inherit; }
54	        a { color: inherit; text-decoration: none; }
55	
56	        /* ── Layout Shell ── */
57	        .shell { display: grid; grid-template-columns: 260px 1fr; min-height: 100vh; }
58	
59	        /* ── Sidebar ── */
60	        .sidebar {
61	            position: sticky; top: 0; height: 100vh;
62	            background: var(--bg-surface);
63	            border-right: 1px solid var(--border);
64	            display: flex; flex-direction: column;
65	            overflow-y: auto;
66	        }
67	        .sidebar-header {
68	            padding: 20px 20px 16px;
69	            border-bottom: 1px solid var(--border);
70	        }
71	        .logo { display: flex; align-items: center; gap: 12px; }
72	        .logo-icon {
73	            width: 36px; height: 36px; border-radius: 10px;
74	            background: linear-gradient(135deg, var(--accent), var(--blue));
75	            display: grid; place-items: center;
76	            font-weight: 800; font-size: 15px; color: #fff;
77	        }
78	        .logo-text { font-size: 15px; font-weight: 700; letter-spacing: 0.04em; }
79	        .logo-sub { font-size: 11px; color: var(--text-muted); margin-top: 1px; }
80	
81	        .runner-widget {
82	            margin: 16px 16px 0;
83	            padding: 14px;
84	            border-radius: var(--radius-md);
85	            background: var(--bg-elevated);
86	            border: 1px solid var(--border);
87	        }
88	        .runner-row { display: flex; align-items: center; gap: 8px; margin-bottom: 10px; }
89	        .dot { width: 8px; height: 8px; border-radius: 50%; background: var(--text-muted); flex-shrink: 0; }
90	        .dot.live { background: var(--green); box-shadow: 0 0 8px var(--green); }
91	        .dot.paused { background: var(--amber); box-shadow: 0 0 8px var(--amber); }
92	        .runner-label { font-size: 13px; font-weight: 600; }
93	        .runner-detail { font-size: 12px; color: var(--text-secondary); margin-bottom: 12px; }
94	        .runner-btns { display: flex; gap: 8px; }
95	
96	        .nav-section { padding: 16px; }
97	        .nav-label {
98	            font-size: 11px; font-weight: 600; text-transform: uppercase;
99	            letter-spacing: 0.08em; color: var(--text-muted);
100	            padding: 0 8px; margin-bottom: 6px;
101	        }
102	        .nav-link {
103	            display: flex; align-items: center; justify-content: space-between;
104	            padding: 9px 12px; border-radius: var(--radius-sm);
105	            color: var(--text-secondary); cursor: pointer;
106	            transition: all var(--transition);
107	        }
108	        .nav-link:hover { background: var(--bg-hover); color: var(--text-primary); }
109	        .nav-link.active { background: var(--accent-soft); color: var(--accent); }
110	        .nav-link .count {
111	            font-size: 11px; padding: 2px 7px; border-radius: 99px;
112	            background: rgba(255,255,255,0.06); color: var(--text-muted);
113	        }
114	        .nav-link.active .count { background: var(--accent-soft); color: var(--accent); }
115	
116	        .sidebar-footer {
117	            margin-top: auto; padding: 16px;
118	            border-top: 1px solid var(--border);
119	            font-size: 12px; color: var(--text-muted);
120	        }
121	        .sidebar-footer .info-row { display: flex; justify-content: space-between; padding: 4px 0; }
122	        .sidebar-footer .info-val { color: var(--text-secondary); }
123	
124	        /* ── Main Content ── */
125	        .main { padding: 24px 28px; overflow-x: hidden; }
126	
127	        /* ── Metric Cards ── */
128	        .metrics { display: grid; grid-template-columns: repeat(5,1fr); gap: 14px; margin-bottom: 24px; }
129	        .metric-card {
130	            padding: 16px 18px;
131	            border-radius: var(--radius-lg);
132	            background: var(--bg-surface);
133	            border: 1px solid var(--border);
134	            transition: border-color var(--transition);
135	        }
136	        .metric-card:hover { border-color: var(--border-strong); }
137	        .metric-label { font-size: 11px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--text-muted); margin-bottom: 8px; }
138	        .metric-value { font-size: 28px; font-weight: 700; line-height: 1; }
139	        .metric-value.total { color: var(--blue); }
140	        .metric-value.running { color: var(--accent); }
141	        .metric-value.waiting { color: var(--amber); }
142	        .metric-value.done { color: var(--green); }
143	        .metric-value.failed { color: var(--rose); }
144	        .metric-hint { font-size: 11px; color: var(--text-muted); margin-top: 6px; }
145	
146	        /* ── Section Panel ── */
147	        .section {
148	            background: var(--bg-surface);
149	            border: 1px solid var(--border);
150	            border-radius: var(--radius-xl);
151	            margin-bottom: 20px;
152	        }
153	        .section-header {
154	            display: flex; align-items: center; justify-content: space-between;
155	            padding: 18px 22px;
156	            border-bottom: 1px solid var(--border);
157	        }
158	        .section-title { font-size: 16px; font-weight: 700; }
159	        .section-desc { font-size: 12px; color: var(--text-muted); margin-top: 2px; }
160	        .section-body { padding: 18px 22px; }
161	
162	        /* ── Pipeline Stepper ── */
163	        .pipeline { display: flex; gap: 0; overflow-x: auto; padding: 4px 0; }
164	        .stage-step {
165	            flex: 1; min-width: 110px; position: relative;
166	            display: flex; flex-direction: column; align-items: center;
167	            padding: 14px 8px; text-align: center;
168	        }
169	        .stage-step::after {
170	            content: ''; position: absolute; top: 24px; left: 50%; width: 100%; height: 2px;
171	            background: var(--border); z-index: 0;
172	        }
173	        .stage-step:last-child::after { display: none; }
174	        .stage-num {
175	            width: 32px; height: 32px; border-radius: 50%;
176	            display: grid; place-items: center;
177	            font-size: 12px; font-weight: 700;
178	            background: var(--bg-elevated); border: 2px solid var(--border-strong);
179	            color: var(--text-muted); position: relative; z-index: 1;
180	            transition: all var(--transition);
181	        }
182	        .stage-step.passed .stage-num,
183	        .stage-step.completed .stage-num { background: var(--green-soft); border-color: var(--green); color: var(--green); }
184	        .stage-step.running .stage-num { background: var(--accent-soft); border-color: var(--accent); color: var(--accent); animation: pulse 2s infinite; }
185	        .stage-step.failed .stage-num { background: var(--rose-soft); border-color: var(--rose); color: var(--rose); }
186	        .stage-step.waiting_human .stage-num { background: var(--amber-soft); border-color: var(--amber); color: var(--amber); }
187	        .stage-step.passed::after,
188	        .stage-step.completed::after { background: var(--green); opacity: 0.4; }
189	        .stage-step.running::after { background: var(--accent); opacity: 0.4; }
190	        .stage-name { font-size: 11px; font-weight: 600; margin-top: 8px; color: var(--text-secondary); text-transform: uppercase; letter-spacing: 0.04em; }
191	        .stage-step.running .stage-name { color: var(--accent); }
192	        .stage-step.passed .stage-name,
193	        .stage-step.completed .stage-name { color: var(--green); }
194	        .stage-status-tag {
195	            font-size: 10px; margin-top: 4px; padding: 2px 8px;
196	            border-radius: 99px; background: rgba(255,255,255,0.05);
197	            color: var(--text-muted);
198	        }
199	        .stage-step.running .stage-status-tag { background: var(--accent-soft); color: var(--accent); }
200	        .stage-step.passed .stage-status-tag,
201	        .stage-step.completed .stage-status-tag { background: var(--green-soft); color: var(--green); }
202	        .stage-step.failed .stage-status-tag { background: var(--rose-soft); color: var(--rose); }
203	        .stage-step.waiting_human .stage-status-tag { background: var(--amber-soft); color: var(--amber); }
204	
205	        /* ── Focus Card (Active Task) ── */
206	        .focus-grid { display: grid; grid-template-columns: 1fr 320px; gap: 18px; margin-bottom: 18px; }
207	        .focus-card {
208	            padding: 18px; border-radius: var(--radius-lg);
209	            background: var(--bg-elevated); border: 1px solid var(--border);
210	        }
211	        .focus-label { font-size: 11px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--text-muted); margin-bottom: 6px; }
212	        .focus-name { font-size: 20px; font-weight: 700; margin-bottom: 4px; }
213	        .focus-desc { font-size: 13px; color: var(--text-secondary); line-height: 1.6; margin-bottom: 14px; max-height: 60px; overflow: hidden; }
214	        .focus-meta { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
215	        .focus-meta-item {
216	            padding: 10px 12px; border-radius: var(--radius-sm);
217	            background: rgba(255,255,255,0.03); border: 1px solid var(--border);
218	        }
219	        .focus-meta-item .fm-label { font-size: 10px; text-transform: uppercase; letter-spacing: 0.06em; color: var(--text-muted); }
220	        .focus-meta-item .fm-value { font-size: 13px; font-weight: 600; margin-top: 3px; }
221	
222	        .health-card {
223	            padding: 18px; border-radius: var(--radius-lg);
224	            background: var(--bg-elevated); border: 1px solid var(--border);
225	            display: flex; flex-direction: column; gap: 14px;
226	        }
227	        .health-title { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.04em; }
228	        .health-big { font-size: 42px; font-weight: 800; line-height: 1; color: var(--accent); }
229	        .progress-track { width: 100%; height: 6px; border-radius: 99px; background: rgba(255,255,255,0.06); overflow: hidden; }
230	        .progress-bar { height: 100%; border-radius: inherit; background: linear-gradient(90deg, var(--accent), var(--blue)); transition: width 0.4s ease; }
231	        .health-rows { display: grid; gap: 8px; }
232	        .health-row { display: flex; justify-content: space-between; font-size: 12px; color: var(--text-secondary); }
233	        .health-row strong { color: var(--text-primary); }
234	
235	        /* ── Two Column Layout ── */
236	        .two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
237	        .three-col { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; }
238	
239	        /* ── Agent Grid ── */
240	        .agent-grid { display: grid; grid-template-columns: 1fr; gap: 10px; max-height: 360px; overflow-y: auto; }
241	        .agent-card {
242	            padding: 14px; border-radius: var(--radius-md);
243	            background: var(--bg-elevated); border: 1px solid var(--border);
244	            transition: border-color var(--transition);
245	        }
246	        .agent-card:hover { border-color: var(--border-strong); }
247	        .agent-top { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 6px; }
248	        .agent-name { font-size: 13px; font-weight: 700; }
249	        .agent-model { font-size: 11px; color: var(--text-muted); }
250	        .agent-role { font-size: 12px; color: var(--text-secondary); margin-bottom: 8px; }
251	        .agent-badges { display: flex; gap: 6px; flex-wrap: wrap; }
252	
253	        /* ── Badges ── */
254	        .badge {
255	            display: inline-flex; align-items: center; gap: 4px;
256	            padding: 3px 9px; border-radius: 99px;
257	            font-size: 11px; font-weight: 600;
258	            background: rgba(255,255,255,0.06); color: var(--text-muted);
259	        }
260	        .badge.running { background: var(--accent-soft); color: var(--accent); }
261	        .badge.passed,.badge.completed { background: var(--green-soft); color: var(--green); }
262	        .badge.failed,.badge.error { background: var(--rose-soft); color: var(--rose); }
263	        .badge.waiting_human { background: var(--amber-soft); color: var(--amber); }
264	        .badge.idle { background: rgba(255,255,255,0.04); color: var(--text-muted); }
265	        .badge.queued { background: var(--blue-soft); color: var(--blue); }
266	
267	        /* ── Buttons ── */
268	        .btn {
269	            appearance: none; border: none; border-radius: var(--radius-sm);
270	            padding: 8px 14px; font-size: 12px; font-weight: 600;
271	            cursor: pointer; color: var(--text-primary);
272	            background: rgba(255,255,255,0.07);
273	            transition: all var(--transition);
274	        }
275	        .btn:hover { background: rgba(255,255,255,0.12); transform: translateY(-1px); }
276	        .btn.primary { background: var(--accent); color: #fff; }
277	        .btn.primary:hover { background: #0891b2; }
278	        .btn.warn { background: var(--amber); color: #1a0d00; }
279	        .btn.warn:hover { background: #d97706; }
280	        .btn.danger { background: var(--rose); color: #fff; }
281	        .btn.ghost { background: transparent; border: 1px solid var(--border); }
282	        .btn.sm { padding: 5px 10px; font-size: 11px; }
283	
284	        /* ── Request Composer ── */
285	        .composer { display: grid; gap: 12px; }
286	        .composer-row { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
287	        .field-group { display: grid; gap: 4px; }
288	        .field-group.full { grid-column: 1 / -1; }
289	        .field-label { font-size: 11px; font-weight: 600; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.04em; }
290	        input, textarea, select {
291	            width: 100%; padding: 10px 14px;
292	            border: 1px solid var(--border); border-radius: var(--radius-sm);
293	            background: var(--bg-base); color: var(--text-primary);
294	            transition: border-color var(--transition);
295	        }
296	        input:focus, textarea:focus { outline: none; border-color: var(--accent); }
297	        textarea { min-height: 100px; resize: vertical; }
298	        .composer-actions { display: flex; gap: 8px; margin-top: 4px; }
299	
300	        /* ── Task Board (Kanban) ── */
301	        .kanban { display: grid; grid-template-columns: repeat(4,1fr); gap: 14px; max-height: 420px; overflow-y: auto; }
302	        .kanban-col {
303	            min-height: 160px; max-height: 400px; overflow-y: auto; padding: 12px;
304	            border-radius: var(--radius-lg);
305	            background: rgba(255,255,255,0.02);
306	            border: 1px solid var(--border);
307	        }
308	        .kanban-col-head {
309	            display: flex; justify-content: space-between; align-items: center;
310	            padding-bottom: 10px; margin-bottom: 10px;
311	            border-bottom: 1px solid var(--border);
312	        }
313	        .kanban-col-title { font-size: 13px; font-weight: 700; }
314	        .kanban-col-count {
315	            font-size: 11px; padding: 2px 8px; border-radius: 99px;
316	            background: rgba(255,255,255,0.06); color: var(--text-muted);
317	        }
318	        .kanban-col.progress { border-top: 2px solid var(--accent); }
319	        .kanban-col.review { border-top: 2px solid var(--amber); }
320	        .kanban-col.done { border-top: 2px solid var(--green); }
321	        .kanban-col.attention { border-top: 2px solid var(--rose); }
322	        .kanban-cards { display: grid; gap: 10px; }
323	
324	        .task-card {
325	            padding: 14px; border-radius: var(--radius-md);
326	            background: var(--bg-elevated); border: 1px solid var(--border);
327	            border-left: 3px solid var(--text-muted);
328	            transition: border-color var(--transition);
329	        }
330	        .task-card:hover { border-color: var(--border-strong); }
331	        .task-card.running { border-left-color: var(--accent); }
332	        .task-card.waiting_human { border-left-color: var(--amber); }
333	        .task-card.completed,.task-card.passed { border-left-color: var(--green); }
334	        .task-card.failed { border-left-color: var(--rose); }
335	        .task-card-head { display: flex; justify-content: space-between; align-items: flex-start; gap: 8px; }
336	        .task-card-title { font-size: 13px; font-weight: 700; }
337	        .task-card-sub { font-size: 11px; color: var(--text-muted); margin-top: 2px; }
338	        .task-card-body { font-size: 12px; color: var(--text-secondary); margin: 8px 0; line-height: 1.5; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
339	        .task-card-progress { margin-top: 8px; }
340	        .task-card-progress-top { display: flex; justify-content: space-between; font-size: 11px; color: var(--text-muted); margin-bottom: 4px; }
341	        .task-microbar { height: 4px; border-radius: 99px; background: rgba(255,255,255,0.06); overflow: hidden; }
342	        .task-microbar span { display: block; height: 100%; border-radius: inherit; background: linear-gradient(90deg, var(--accent), var(--blue)); }
343	        .task-card-badges { display: flex; gap: 4px; flex-wrap: wrap; margin-top: 8px; }
344	
345	        /* ── Approval Cards ── */
346	        .approval-card {
347	            padding: 16px; border-radius: var(--radius-md);
348	            background: var(--bg-elevated); border: 1px solid var(--amber-soft);
349	            border-left: 3px solid var(--amber);
350	        }
351	        .approval-head { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 8px; }
352	        .approval-title { font-size: 14px; font-weight: 700; }
353	        .approval-sub { font-size: 12px; color: var(--text-muted); margin-top: 2px; }
354	        .approval-reason { font-size: 12px; color: var(--text-secondary); margin-bottom: 12px; }
355	        .approval-actions { display: flex; gap: 8px; }
356	
357	        /* ── Event Feed ── */
358	        .feed { max-height: 400px; overflow-y: auto; display: grid; gap: 6px; }
359	        .feed-item {
360	            padding: 10px 14px; border-radius: var(--radius-sm);
361	            background: rgba(255,255,255,0.02);
362	            border: 1px solid transparent;
363	            transition: background var(--transition);
364	        }
365	        .feed-item:hover { background: rgba(255,255,255,0.04); }
366	        .feed-top { display: flex; align-items: center; gap: 8px; margin-bottom: 4px; }
367	        .feed-dot { width: 6px; height: 6px; border-radius: 50%; flex-shrink: 0; background: var(--text-muted); }
368	        .feed-dot.info { background: var(--blue); }
369	        .feed-dot.success { background: var(--green); }
370	        .feed-dot.warning { background: var(--amber); }
371	        .feed-dot.error { background: var(--rose); }
372	        .feed-time { font-size: 11px; color: var(--text-muted); }
373	        .feed-source { font-size: 11px; color: var(--text-muted); }
374	        .feed-stage-tag { font-size: 10px; padding: 1px 6px; border-radius: 99px; background: rgba(255,255,255,0.05); color: var(--text-muted); }
375	        .feed-msg { font-size: 12px; color: var(--text-secondary); line-height: 1.5; }
376	
377	        .feed-filter { display: flex; gap: 6px; flex-wrap: wrap; }
378	        .feed-filter .btn { font-size: 11px; padding: 4px 10px; }
379	        .feed-filter .btn.active { background: var(--accent-soft); color: var(--accent); }
380	
381	        /* ── Empty State ── */
382	        .empty {
383	            padding: 24px; text-align: center;
384	            border: 1px dashed var(--border-strong);
385	            border-radius: var(--radius-md);
386	            color: var(--text-muted); font-size: 13px;
387	        }
388	
389	        /* ── Artifact Panel ── */
390	        .artifact-stages { display: grid; gap: 14px; max-height: 500px; overflow-y: auto; }
391	        .artifact-stage-header {
392	            display: flex; align-items: center; justify-content: space-between;
393	            padding: 10px 14px; border-radius: var(--radius-sm);
394	            background: var(--bg-elevated); border: 1px solid var(--border);
395	            cursor: pointer; user-select: none;
396	            transition: background var(--transition);
397	        }
398	        .artifact-stage-header:hover { background: var(--bg-hover); }
399	        .artifact-stage-name { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.04em; }
400	        .artifact-stage-count { font-size: 11px; color: var(--text-muted); }
