815	function fmtDuration(startStr, endStr) {
816	    if (!startStr) return '';
817	    const start = new Date(startStr);
818	    const end = endStr ? new Date(endStr) : new Date();
819	    const sec = Math.round((end - start) / 1000);
820	    if (sec < 60) return `${sec}s`;
821	    const min = Math.floor(sec / 60);
822	    const s = sec % 60;
823	    if (min < 60) return `${min}m${s}s`;
824	    return `${Math.floor(min/60)}h${min%60}m`;
825	}
826	function taskDuration(task) {
827	    if (!task) return '-';
828	    const stages = task.stages || {};
829	    let earliest = null, latest = null;
830	    for (const s of Object.values(stages)) {
831	        if (s.started_at) { const d = new Date(s.started_at); if (!earliest || d < earliest) earliest = d; }
832	        if (s.ended_at) { const d = new Date(s.ended_at); if (!latest || d > latest) latest = d; }
833	    }
834	    if (!earliest) return '-';
835	    if (!latest && task.status === 'running') latest = new Date();
836	    if (!latest) return '-';
837	    return fmtDuration(earliest.toISOString(), latest.toISOString());
838	}
