841	    if (!task) return '<div class="empty">暂无活动任务</div>';
842	    const stageMap = task.stages || {};
843	    return `<div class="pipeline">${STAGES.map((s,i) => {
844	        const item = stageMap[s] || {status:'pending'};
845	        const dur = (item.started_at && item.status !== 'pending') ? fmtDuration(item.started_at, item.ended_at) : '';
846	        return `<div class="stage-step ${statusCls(item.status)} ${item.status==='running'?'pulse':''}">
847	            <div class="stage-num">${i+1}</div>
848	            <div class="stage-name">${esc(humanStage(s))}</div>
849	            <div class="stage-status-tag">${esc(item.status||'pending')}${dur ? ' · '+dur : ''}</div>
850	        </div>`;
851	    }).join('')}</div>`;
852	}
