854	function renderKanban(tasks) {
855	    if (!tasks.length) return '<div class="empty">还没有任务。先提交一个请求。</div>';
856	    const cols = [
857	        {key:'progress',title:'In Progress',cls:'progress'},
858	        {key:'review',title:'In Review',cls:'review'},
859	        {key:'done',title:'Done',cls:'done'},
860	        {key:'attention',title:'Needs Attention',cls:'attention'}
861	    ];
862	    const grouped = {}; cols.forEach(c=>grouped[c.key]=[]);
863	    tasks.forEach(t=>grouped[classifyTask(t)].push(t));
864	    return `<div class="kanban">${cols.map(col => {
865	        const items = grouped[col.key];
866	        return `<div class="kanban-col ${col.cls}">
867	            <div class="kanban-col-head"><span class="kanban-col-title">${col.title}</span><span class="kanban-col-count">${items.length}</span></div>
868	            <div class="kanban-cards">${items.length ? items.map(t => {
869	                const p = taskPct(t);
870	                const badges = Object.entries(t.stages||{}).filter(([,v])=>v.status&&v.status!=='pending').slice(-3).map(([s,v])=>`<span class="badge ${statusCls(v.status)}">${esc(humanStage(s))}</span>`).join('');
871	                return `<div class="task-card ${statusCls(t.status)}">
872	                    <div class="task-card-head"><div><div class="task-card-title">${esc(t.title||'Untitled')}</div><div class="task-card-sub">${esc(t.source||'unknown')} · ${esc(humanStage(t.current_stage||'queued'))}</div></div><span class="badge ${statusCls(t.status)}">${esc(t.status||'queued')}</span></div>
873	                    <div class="task-card-body">${esc(t.request_text||'')}</div>
874	                    <div class="task-card-progress"><div class="task-card-progress-top"><span>${esc(t.id||'-')}</span><span>${p}%</span></div><div class="task-microbar"><span style="width:${p}%"></span></div></div>
875	                    <div class="task-card-badges">${badges||'<span class="badge queued">queued</span>'}${t.status==='failed'?`<button class="btn danger sm" style="margin-left:auto" onclick="retryTask('${esc(t.id)}')">从失败处继续</button>`:''}</div>
876	                </div>`;
877	            }).join('') : '<div class="empty">无</div>'}</div>
878	        </div>`;
879	    }).join('')}</div>`;
880	}
