909	async function loadArtifacts(taskId) {
910	    artifactTaskId = taskId;
911	    openArtifacts.clear();
912	    const ab = document.getElementById('artifact-body');
913	    if (!taskId) {
914	        if (ab) ab.innerHTML = '<div class="empty">选择一个任务查看产物</div>';
915	        return;
916	    }
917	    if (ab) ab.innerHTML = '<div class="empty">加载中...</div>';
918	    if (!artifactCache[taskId]) {
919	        const r = await fetch(`/api/tasks/${taskId}/artifacts`);
920	        artifactCache[taskId] = await r.json();
921	    }
922	    if (ab) ab.innerHTML = renderArtifacts(artifactCache[taskId]);
923	}
