932	function downloadArtifact(name, content) {
933	    const blob = new Blob([content], {type: 'text/plain;charset=utf-8'});
934	    const url = URL.createObjectURL(blob);
935	    const a = document.createElement('a');
936	    a.href = url; a.download = name; a.click();
937	    URL.revokeObjectURL(url);
938	}
