940	function renderArtifacts(data) {
941	    if (!data || !Object.keys(data).length) return '<div class="empty">该任务暂无产物</div>';
942	    let counter = 0;
943	    return `<div class="artifact-stages">${STAGES.map(stage => {
944	        const files = data[stage];
945	        if (!files || !files.length) return '';
946	        return `<div>
947	            <div class="artifact-stage-header" onclick="this.nextElementSibling.style.display=this.nextElementSibling.style.display==='none'?'grid':'none'">
948	                <span class="artifact-stage-name">${esc(humanStage(stage))}</span>
949	                <span class="artifact-stage-count">${files.length} file${files.length>1?'s':''}</span>
950	            </div>
951	            <div class="artifact-files" style="display:none">${files.map(f => {
952	                const id = 'af-' + (counter++);
953	                const isJson = f.name.endsWith('.json');
954	                const display = isJson ? (()=>{ try { return JSON.stringify(JSON.parse(f.content),null,2); } catch(e) { return f.content; } })() : f.content;
955	                const isOpen = openArtifacts.has(id);
956	                return `<div class="artifact-file">
957	                    <div class="artifact-file-header" onclick="toggleArtifact('${id}')">
958	                        <div>
959	                            <div class="artifact-file-name">${esc(f.name)}</div>
960	                            <div class="artifact-file-path">${esc(f.path)}</div>
961	                        </div>
962	                        <div style="display:flex;gap:8px;align-items:center">
963	                            <button class="btn ghost sm" onclick="event.stopPropagation();downloadArtifact('${esc(f.name)}',artifactCache['${esc(artifactTaskId)}']['${esc(stage)}'][${files.indexOf(f)}].content)">下载</button>
964	                            <span class="artifact-file-toggle">${isOpen?'▲':'▼'}</span>
965	                        </div>
966	                    </div>
967	                    <div class="artifact-content ${isOpen?'open':''}" id="${id}"><pre>${esc(display)}</pre></div>
968	                </div>`;
969	            }).join('')}</div>
970	        </div>`;
971	    }).join('')}</div>`;
972	}
