991	/* ── Pipeline Editor ── */
992	const ALL_STAGES = [
993	    {id:'intake', name:'Request Intake', agent:'planner'},
994	    {id:'planning', name:'Sprint Planning', agent:'planner'},
995	    {id:'requirements', name:'Requirements', agent:'requirements-analyst'},
996	    {id:'design', name:'System Design', agent:'system-architect'},
997	    {id:'development', name:'Implementation', agent:'developer'},
998	    {id:'code_review', name:'Code Review', agent:'code-reviewer'},
999	    {id:'security_review', name:'Security Review', agent:'security-reviewer'},
1000	    {id:'testing', name:'QA Testing', agent:'qa-engineer'},
1001	    {id:'delivery', name:'Gerrit Delivery', agent:'delivery-manager'},
1002	];
1003	let editorStages = [];
1004	let editorLoaded = false;
1005	let dragIdx = null;
1006	let pipelineIsCustom = false;
1007	let pipelineFetched = false;
1008	let renderThrottleTimer = null;
1009	
1010	function initPipelineEditor() {
1011	    if (!editorLoaded) {
1012	        editorStages = STAGES.map(id => ALL_STAGES.find(s=>s.id===id) || {id, name:id, agent:'-'});
1013	        editorLoaded = true;
1014	    }
1015	    // Update mode tag and restore button
1016	    const tag = document.getElementById('pipe-mode-tag');
1017	    const btn = document.getElementById('pipe-restore-btn');
1018	    if (tag) tag.textContent = pipelineIsCustom ? '当前: 自定义' : '当前: 系统默认';
1019	    if (btn) btn.style.display = pipelineIsCustom ? '' : 'none';
1020	    renderPipelineEditor();
1021	}
