1023	function renderPipelineEditor() {
1024	    const body = document.getElementById('pipe-editor-body');
1025	    if (!body) return;
1026	    const usedIds = new Set(editorStages.map(s=>s.id));
1027	    const available = ALL_STAGES.filter(s=>!usedIds.has(s.id));
1028	    body.innerHTML = `
1029	        <div class="pipe-editor" id="pipe-sortable">
1030	            ${editorStages.map((s,i) => `
1031	                <div class="pipe-item" draggable="true" data-idx="${i}"
1032	                     ondragstart="pipeDragStart(event,${i})" ondragover="pipeDragOver(event,${i})"
1033	                     ondragleave="pipeDragLeave(event)" ondrop="pipeDrop(event,${i})" ondragend="pipeDragEnd(event)">
1034	                    <span class="pipe-num">${i+1}</span>
1035	                    <span class="pipe-name">${esc(s.name)}</span>
1036	                    <span class="pipe-agent">${esc(s.agent)}</span>
1037	                    <span class="pipe-remove" onclick="pipeRemove(${i})">×</span>
1038	                </div>
1039	            `).join('')}
1040	        </div>
1041	        <div class="pipe-add-row">
1042	            <select class="artifact-task-select pipe-add-select" id="pipe-add-select">
1043	                <option value="">添加 stage...</option>
1044	                ${available.map(s=>`<option value="${esc(s.id)}">${esc(s.name)} (${esc(s.agent)})</option>`).join('')}
1045	            </select>
1046	            <button class="btn ghost sm" onclick="pipeAdd()">添加</button>
1047	        </div>`;
1048	}
