1050	function pipeDragStart(e, idx) { dragIdx = idx; e.target.classList.add('dragging'); }
1051	function pipeDragOver(e, idx) { e.preventDefault(); e.currentTarget.classList.add('drag-over'); }
1052	function pipeDragLeave(e) { e.currentTarget.classList.remove('drag-over'); }
1053	function pipeDragEnd(e) { e.target.classList.remove('dragging'); document.querySelectorAll('.drag-over').forEach(el=>el.classList.remove('drag-over')); }
1054	function pipeDrop(e, toIdx) {
1055	    e.preventDefault(); e.currentTarget.classList.remove('drag-over');
1056	    if (dragIdx === null || dragIdx === toIdx) return;
1057	    const item = editorStages.splice(dragIdx, 1)[0];
1058	    editorStages.splice(toIdx, 0, item);
1059	    dragIdx = null;
1060	    renderPipelineEditor();
1061	}
1062	function pipeRemove(idx) { editorStages.splice(idx, 1); renderPipelineEditor(); }
1063	function pipeAdd() {
1064	    const sel = document.getElementById('pipe-add-select');
1065	    if (!sel || !sel.value) return;
1066	    const stage = ALL_STAGES.find(s=>s.id===sel.value);
1067	    if (stage) { editorStages.push(stage); renderPipelineEditor(); }
1068	}
1069	function resetPipelineEditor() {
1070	    editorStages = STAGES.map(id => ALL_STAGES.find(s=>s.id===id) || {id, name:id, agent:'-'});
1071	    renderPipelineEditor();
1072	}
1073	async function savePipeline() {
1074	    const stages = editorStages.map(s => ({id: s.id, name: s.name, agent: s.agent}));
1075	    const r = await fetch('/api/pipeline', {
1076	        method: 'POST',
1077	        headers: {'Content-Type':'application/json'},
1078	        body: JSON.stringify({stages})
1079	    });
1080	    const data = await r.json();
1081	    pipelineIsCustom = data.is_custom ?? true;
1082	    pipelineFetched = true;
1083	    await fetchRuntime();
1084	    editorLoaded = false;
1085	    initPipelineEditor();
1086	}
1087	async function restoreDefaultPipeline() {
1088	    await fetch('/api/pipeline/reset', {method:'POST'});
1089	    pipelineIsCustom = false;
1090	    pipelineFetched = true;
1091	    await fetchRuntime();
1092	    editorLoaded = false;
1093	    initPipelineEditor();
1094	}
