1096	/* ── SSE ── */
1097	function connectStream() {
1098	    if (eventSource) eventSource.close();
1099	    eventSource = new EventSource('/api/stream');
1100	    eventSource.onmessage = (msg) => {
1101	        const ev = JSON.parse(msg.data);
1102	        latestEvents.push(ev);
1103	        latestEvents = latestEvents.slice(-200);
1104	        // Throttle: batch SSE events, refresh at most every 2s
1105	        if (!renderThrottleTimer) {
1106	            renderThrottleTimer = setTimeout(async () => {
1107	                renderThrottleTimer = null;
1108	                await fetchRuntime();
1109	            }, 2000);
1110	        }
1111	    };
1112	    eventSource.onerror = () => setTimeout(connectStream, 3000);
1113	}
1114	
1115	/* ── Boot ── */
1116	fetchRuntime().then(connectStream);
1117	setInterval(fetchRuntime, 15000);
1118	</script>
